+  it("builds channel routes for thread conversations and strips suffix metadata", () => {
+    const route = resolveMSTeamsOutboundSessionRoute({
+      cfg: {},
+      agentId: "main",
+      accountId: "default",
+      target: "teams:19:abc123@thread.tacv2;messageid=42",
