+    });
+
+    it("rethrows non-revoked errors", async () => {
+      const err = Object.assign(new Error("boom"), { statusCode: 500 });
+      await expect(
+        withRevokedProxyFallback({
+          run: async () => {
+            throw err;
+          },
+          onRevoked: async () => "fallback",
+        }),
+      ).rejects.toBe(err);
+    });
+  });
 });

